-- EasyWin Import: Reference Tables
SET client_encoding = 'UTF8';

TRUNCATE regioni CASCADE;
SELECT setval('regioni_id_seq', (SELECT COALESCE(MAX(id),0) FROM regioni));

TRUNCATE province CASCADE;
SELECT setval('province_id_seq', (SELECT COALESCE(MAX(id),0) FROM province));

TRUNCATE criteri CASCADE;
SELECT setval('criteri_id_seq', (SELECT COALESCE(MAX(id),0) FROM criteri));

TRUNCATE tipologia_bandi CASCADE;
SELECT setval('tipologia_bandi_id_seq', (SELECT COALESCE(MAX(id),0) FROM tipologia_bandi));

TRUNCATE tipologia_gare CASCADE;
SELECT setval('tipologia_gare_id_seq', (SELECT COALESCE(MAX(id),0) FROM tipologia_gare));

TRUNCATE tipo_dati_gara CASCADE;
SELECT setval('tipo_dati_gara_id_seq', (SELECT COALESCE(MAX(id),0) FROM tipo_dati_gara));

TRUNCATE piattaforme CASCADE;
SELECT setval('piattaforme_id_seq', (SELECT COALESCE(MAX(id),0) FROM piattaforme));